import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;

public class DeepLinkHandlerActivity extends AppCompatActivity {

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        handleDeepLink(getIntent());
    }

    @Override
    protected void onNewIntent(@NonNull Intent intent) {
        super.onNewIntent(intent);
        handleDeepLink(intent);
    }

    private void handleDeepLink(Intent intent) {
        if (intent != null && Intent.ACTION_VIEW.equals(intent.getAction())) {
            Uri data = intent.getData();
            if (data != null) {
                String path = data.getPath();
                if (path != null) {
                    navigateToScreen(path);
                }
            }
        }
    }

    private void navigateToScreen(String path) {
        switch (path) {
            case "/profile/123":
                // Navigate to ProfileActivity
                startActivity(new Intent(this, ProfileActivity.class));
                break;
            case "/payment/confirm":
                // Navigate to PaymentConfirmationActivity
                startActivity(new Intent(this, PaymentConfirmationActivity.class));
                break;
            case "/admin/settings":
                // Navigate to AdminSettingsActivity
                startActivity(new Intent(this, AdminSettingsActivity.class));
                break;
            default:
                // Handle unknown paths or show an error
                break;
        }
    }
}